<?php require_once __DIR__.'/../includes/functions.php'; require_once __DIR__.'/../includes/db.php'; require_admin(); include 'partials/header.php'; include 'partials/sidebar.php'; $q='%'.($_GET['q']??'').'%'; $st=db()->prepare('SELECT * FROM bookings WHERE full_name LIKE ? OR phone LIKE ? OR city LIKE ? OR package_type LIKE ? OR status LIKE ? ORDER BY created_at DESC'); $st->execute([$q,$q,$q,$q,$q]); ?><h2 class="mb-4 text-3xl font-black">Bookings</h2><form class="mb-4"><input name="q" value="<?=e($_GET['q']??'')?>" class="w-full rounded border p-3" placeholder="Search by name, phone, city, package type, status"></form><div class="overflow-auto rounded-2xl bg-white shadow"><table class="min-w-full text-sm"><tr class="bg-slate-950 text-white"><th class="p-3">Name</th><th>Phone</th><th>City</th><th>Package</th><th>Persons</th><th>Date</th><th>Status</th></tr><?php foreach($st as $r):?><tr class="border-t"><td class="p-3"><?=e($r['full_name'])?></td><td><?=e($r['phone'])?></td><td><?=e($r['city'])?></td><td><?=e($r['package_type'])?><br><small><?=e($r['special_request'])?></small></td><td><?=e($r['number_of_persons'])?></td><td><?=e($r['preferred_travel_date'])?></td><td><form method="post" action="status-update.php"><input type="hidden" name="csrf_token" value="<?=e(csrf_token())?>"><input type="hidden" name="table" value="bookings"><input type="hidden" name="id" value="<?=e($r['id'])?>"><select name="status" onchange="this.form.submit()"><?php foreach(['New','Contacted','Confirmed','Cancelled','Completed'] as $s):?><option <?=$r['status']===$s?'selected':''?>><?=$s?></option><?php endforeach;?></select></form></td></tr><?php endforeach;?></table></div><?php include 'partials/footer.php'; ?>
